    }

    await client.query("COMMIT");
    client.release();
    return true;
  } catch (err) {
    console.error("Neon database save failed", err);
    try {
      const client = await pool.connect();
      await client.query("ROLLBACK");
      client.release();
    } catch (e) {}
    return false;
