// Lightweight .gitignore glob-to-regex converter
function globToRegex(pattern: string): RegExp {
  let neg = false;
  let p = pattern.trim();
  if (!p || p.startsWith('#')) return /(?!)/; // never matches
  if (p.startsWith('!')) { neg = true; p = p.slice(1); }
  p = p.replace(/\/$/, '');
  let regexStr = p
    .replace(/\./g, '\\.')
    .replace(/\*\*/g, '{{GLOBSTAR}}')
    .replace(/\*/g, '[^/]*')
    .replace(/\?/g, '[^/]')
    .replace(/\{\{GLOBSTAR\}\}/g, '.*');
  if (!p.includes('/')) {
    regexStr = '(^|.*/)'+ regexStr + '(/.*)?$';
  } else {
    regexStr = '^' + regexStr + '(/.*)?$';
  }
  return new RegExp(regexStr);
}

