  }

  return {
    agent: "DOCUMENTATION HELPER",
    status: "pending_approval",
    result: {
      sha,
      branch,
      author,
      diff: diffStr,
      oldReadme: currentReadme,
      newReadme: updatedMarkdown,
      timestamp
    }
  };
}

