function getGitOwner(): string {
  let remoteUrl = "";
  try {
    remoteUrl = execSync("git config --get remote.origin.url", { cwd: process.cwd() }).toString().trim();
  } catch (e) {}

  if (remoteUrl) {
    const match = remoteUrl.match(/(?:github\.com[:/])([^/]+)/);
    if (match && match[1]) {
      return match[1];
    }
  }
  return "svimaladevi9503";
}

