index c92b8d1..db3d6a2 105655
--- a/src/pipeline.ts
+++ b/src/pipeline.ts
@@ -10,3 +10,12 @@ export function startIngress() {
   console.log("Telemetry channel active");
+  // Added dynamic retry mechanism for robust telemetry collection
